// C:\Users\larho\suka-smart-assistant\src\features\bookmarklet\bookmarklet.min.js
// Prebuilt, ready-to-serve bookmarklet runtime (expanded to support cleaning, garden care,
// harvest, storehouse stock (grocery sections), meal planning, animal acquisition, care,
// and butchery). Mirrors generateBookmarklet.js logic.
// -----------------------------------------------------------------------------
(function () {
  var OFFLINE_KEY = "suka.bookmarklet.offlineQueue.v1";
  var DEFAULTS = {
    sourceType: "bookmarklet",
    saveAsFavorite: false,
    autoSchedule: false,
    autoScheduleRule: "once+5min",
    forceImportType: null,
    reverseMeta: {
      shareTarget: "family-fund-hub",
      includeShare: true,
      format: "json",
      reverseFromId: null
    }
  };

  // --------------------------------------------
  // tiny text helpers
  // --------------------------------------------
  function collectText(doc, max) {
    var nodes = doc.querySelectorAll("p, li, article, section");
    var out = [];
    for (var i = 0; i < nodes.length && out.length < max; i++) {
      var t = (nodes[i].textContent || "").trim();
      if (t) out.push(t);
    }
    return out;
  }

  function guessCleaning(txt) {
    return /clean|declutter|organize|bathroom|kitchen|laundry|mop|dust|chore/i.test(txt);
  }
  function guessGardenCare(txt) {
    return /water(ing)?|fertiliz(e|er)|mulch|prune|trellis|pest control|aphid|blight/i.test(txt);
  }
  function guessHarvest(txt) {
    return /harvest|when to pick|curing|drying|canning|fermenting|root cellar|storage/i.test(txt);
  }
  function guessStorehouseStock(txt, url) {
    return /weekly ad|circular|grocery|kroger|walmart|aldi|heb|publix|food lion|costco|sams/i.test(txt) ||
      /weekly-ads?|circular|flyer/i.test(url);
  }
  function guessAnimalAcq(txt, url) {
    return /livestock|goats?|sheep|lambs?|calves?|heifer|poultry|chickens?|ducks?|rabbits?/i.test(txt) ||
      /farm|tractor|rural|agric|auction/i.test(url);
  }
  function guessButchery(txt) {
    return /butcher|butchery|slaughter|meat cutting|cut sheet|processing|usda inspected|halal/i.test(txt);
  }

  // --------------------------------------------
  // detectType
  // --------------------------------------------
  function detectType(host, href, pageText, force) {
    if (force) return force;
    if (/pinterest\.com/i.test(host)) return "mealPlan";
    if (/seed|nursery|garden|grow|burpee|johnnyseeds|gardeningknowhow/i.test(href)) {
      if (guessGardenCare(pageText)) return "gardenCare";
      if (guessHarvest(pageText)) return "harvestPlan";
      return "gardenPlan";
    }
    if (guessStorehouseStock(pageText, href)) return "storehouseStock";
    if (guessCleaning(pageText)) return "cleaningPlan";
    if (guessAnimalAcq(pageText, href)) return "animalAcquisition";
    if (guessButchery(pageText)) return "butcherySession";
    if (/youtube\.com|youtu\.be/i.test(host)) return "recipe";
    if (/allrecipes\.com|loveandlemons\.com|foodnetwork\.com|seriouseats\.com|eatingwell\.com/i.test(host)) return "recipe";
    return "recipe";
  }

  // --------------------------------------------
  // scrape
  // --------------------------------------------
  function scrape(doc, win, opts) {
    var hostname = win.location.hostname || "";
    var href = win.location.href || "";
    var texts = collectText(doc, 120);
    var pageText = texts.join("\n").toLowerCase();

    var detectedType = detectType(hostname, href, pageText, opts.forceImportType);

    var sel = "";
    try {
      sel =
        (win.getSelection && win.getSelection().toString()) ||
        (doc.getSelection && doc.getSelection().toString()) ||
        "";
      sel = (sel || "").trim();
    } catch (_) {}

    var ogTitle = (doc.querySelector('meta[property="og:title"]') || {}).content;
    var ogUrl = (doc.querySelector('meta[property="og:url"]') || {}).content;
    var ogImg = (doc.querySelector('meta[property="og:image"]') || {}).content;
    var ogDesc = (doc.querySelector('meta[property="og:description"]') || {}).content;

    var listItems = Array.prototype.slice
      .call(doc.querySelectorAll("li, .ingredient, .ingredients li"))
      .map(function (el) {
        return (el.textContent || "").trim();
      })
      .filter(function (t) {
        return t && t.length < 190;
      })
      .slice(0, 80);

    var payload = {
      __importType: detectedType,
      title: doc.title || ogTitle || "Imported Page",
      url: href,
      source: {
        kind: "bookmarklet",
        url: href,
        title: doc.title || ogTitle || "",
        hostname: hostname,
        og: {
          title: ogTitle,
          url: ogUrl,
          image: ogImg,
          description: ogDesc
        }
      },
      meta: {
        selectedText: sel,
        timestamp: Date.now()
      },
      saveAsFavorite: !!opts.saveAsFavorite,
      reverseMeta: opts.reverseMeta || DEFAULTS.reverseMeta
    };

    // ----------------------------------------
    // per-type shaping
    // ----------------------------------------

    // recipe
    if (detectedType === "recipe") {
      payload.ingredients = listItems;
      var paras = Array.prototype.slice
        .call(doc.querySelectorAll("p"))
        .map(function (p) {
          return (p.textContent || "").trim();
        })
        .filter(Boolean)
        .slice(0, 40);
      payload.steps = paras.length ? paras : sel ? [sel] : [];
      payload.usesAnimalProduct =
        /beef|lamb|goat|mutton|chicken|turkey|duck|fish|eggs?|cheese|milk/i.test(pageText) || false;
    }

    // pinterest → mealPlan
    if (detectedType === "mealPlan") {
      payload.days = [
        {
          date: null,
          meals: [ogTitle || doc.title || "Meal Idea"]
        }
      ];
      payload.collaborative = true;
    }

    // garden plan
    if (detectedType === "gardenPlan") {
      payload.seeds = listItems.map(function (name) {
        return { name: name };
      });
      payload.zone = null;
      payload.coop = true;
      payload.careProfile = null;
    }

    // garden care
    if (detectedType === "gardenCare") {
      payload.zones = [
        {
          id: "default",
          name: "Garden Zone",
          tasks: listItems.length ? listItems : ["Water", "Fertilize", "Inspect for pests"]
        }
      ];
      payload.cadence = "2x/week";
      payload.session = {
        kind: "garden-care",
        date: null,
        recurring: null,
        tasks: listItems.slice(0, 20)
      };
    }

    // harvest plan
    if (detectedType === "harvestPlan") {
      payload.crops = listItems.map(function (crop) {
        return {
          crop: crop,
          expectedDate: null,
          quantity: null,
          unit: null,
          toStorehouse: true,
          preserveMethod: /can|ferment|dry|freeze/i.test(pageText) ? "preserve" : null
        };
      });
      payload.session = {
        kind: "garden-harvest",
        date: null,
        recurring: null,
        tasks: listItems.slice(0, 20)
      };
    }

    // cleaning plan
    if (detectedType === "cleaningPlan") {
      payload.rooms = [
        {
          name: "Home",
          tasks: listItems.length ? listItems : ["Clear surfaces", "Vacuum", "Mop", "Bathrooms"],
          supplies: ["All-purpose cleaner", "Microfiber cloths"]
        }
      ];
      payload.cadence = /weekly|every week/i.test(pageText) ? "weekly" : "daily";
      payload.batchable = true;
      payload.session = {
        kind: "cleaning",
        date: null,
        recurring: null,
        tasks: listItems.slice(0, 30)
      };
    }

    // storehouse stock (grocery sections)
    if (detectedType === "storehouseStock") {
      var sections = [];
      var produce = [], dairy = [], meat = [], dry = [], freezer = [];
      listItems.forEach(function (it) {
        var low = it.toLowerCase();
        if (/lettuce|onion|pepper|apple|banana|greens?|tomato|potato|carrot/.test(low)) produce.push(it);
        else if (/milk|cheese|butter|yogurt|cream/.test(low)) dairy.push(it);
        else if (/beef|chicken|lamb|goat|turkey|fish|pork/.test(low)) meat.push(it);
        else if (/rice|beans|flour|cornmeal|pasta|oats?/.test(low)) dry.push(it);
        else freezer.push(it);
      });
      if (produce.length) sections.push({ section: "produce", items: produce.map(function (item) { return { item: item, targetQty: null, unit: null, preserveMethod: null }; }) });
      if (dairy.length) sections.push({ section: "dairy", items: dairy.map(function (item) { return { item: item, targetQty: null, unit: null, preserveMethod: null }; }) });
      if (meat.length) sections.push({ section: "meat", items: meat.map(function (item) { return { item: item, targetQty: null, unit: null, preserveMethod: "freeze" }; }) });
      if (dry.length) sections.push({ section: "pantry", items: dry.map(function (item) { return { item: item, targetQty: null, unit: null, preserveMethod: null }; }) });
      if (freezer.length) sections.push({ section: "frozen-or-other", items: freezer.map(function (item) { return { item: item, targetQty: null, unit: null, preserveMethod: "freeze" }; }) });
      if (!sections.length) {
        sections.push({
          section: "general",
          items: listItems.map(function (item) { return { item: item, targetQty: null, unit: null, preserveMethod: null }; })
        });
      }
      payload.sections = sections;
      payload.session = {
        kind: "storehouse-restock",
        date: null,
        recurring: null,
        tasks: listItems.slice(0, 30)
      };
    }

    // animal acquisition
    if (detectedType === "animalAcquisition") {
      payload.needs = listItems.length
        ? listItems.map(function (line) {
            var low = line.toLowerCase();
            var guess =
              /goat/.test(low) ? "goat" :
              /sheep|lamb/.test(low) ? "sheep" :
              /chicken|poultry|hen/.test(low) ? "chicken" :
              /duck/.test(low) ? "duck" :
              /rabbit/.test(low) ? "rabbit" : "livestock";
            return {
              species: guess,
              breed: null,
              qty: null,
              reason: "Imported from page",
              targetDate: null
            };
          })
        : [
            {
              species: "livestock",
              breed: null,
              qty: null,
              reason: "Imported from page",
              targetDate: null
            }
          ];
      payload.session = {
        kind: "inventory-sync",
        date: null,
        recurring: null,
        tasks: listItems.slice(0, 20)
      };
    }

    // butchery session
    if (detectedType === "butcherySession") {
      payload.animals = [
        {
          species: "livestock",
          qty: null,
          cuts: []
        }
      ];
      payload.processingTasks = listItems.length ? listItems : ["slaughter", "eviscerate", "quarter", "grind", "pack", "freeze"];
      payload.links = {
        recipes: [],
        mealPlans: [],
        storehouseGoals: [],
        inventoryUpdates: []
      };
      payload.session = {
        kind: "butchery",
        date: null,
        recurring: null,
        tasks: listItems.slice(0, 30)
      };
    }

    // optional schedule
    if (opts.autoSchedule) {
      payload.schedule = {
        rule: opts.autoScheduleRule || "once+5min",
        createdAt: Date.now()
      };
    }

    return payload;
  }

  // --------------------------------------------
  // deliver to Suka (DOM + eventBus + localStorage fallback)
  // --------------------------------------------
  function deliver(payload) {
    var delivered = false;
    // 1. DOM event
    try {
      var ev = new CustomEvent("import.queue.enqueue", {
        detail: {
          sourceType: payload.__importType === "mealPlan" ? "pinterest" : "bookmarklet",
          payload: payload,
          opts: {
            saveAsFavorite: !!payload.saveAsFavorite,
            schedule: payload.schedule || null,
            session: payload.session || null,
            label: payload.title
          }
        }
      });
      window.dispatchEvent(ev);
      delivered = true;
    } catch (e) {}

    // 2. Suka event bus
    try {
      if (window.__suka && window.__suka.eventBus && typeof window.__suka.eventBus.emit === "function") {
        window.__suka.eventBus.emit("import.queue.enqueue", {
          sourceType: payload.__importType === "mealPlan" ? "pinterest" : "bookmarklet",
          payload: payload,
          opts: {
            saveAsFavorite: !!payload.saveAsFavorite,
            schedule: payload.schedule || null,
            session: payload.session || null,
            label: payload.title
          }
        });
        delivered = true;
      }
    } catch (e2) {}

    // 3. fallback to localStorage
    if (!delivered) {
      try {
        var raw = window.localStorage.getItem(OFFLINE_KEY);
        var arr = raw ? JSON.parse(raw) : [];
        arr.unshift({ at: Date.now(), payload: payload });
        window.localStorage.setItem(OFFLINE_KEY, JSON.stringify(arr.slice(0, 50)));
        alert("Suka: App not open → saved import locally. Open Suka to pull it in.");
      } catch (e3) {
        alert("Suka: Unable to deliver import.");
      }
    } else {
      alert("Suka: Import sent!");
    }
  }

  // --------------------------------------------
  // MAIN
  // --------------------------------------------
  try {
    var d = document;
    var w = window;
    // change DEFAULTS below to build “special” bookmarklets (e.g. forceImportType: "cleaningPlan")
    var userOpts = DEFAULTS;
    var payload = scrape(d, w, userOpts);
    deliver(payload);
  } catch (err) {
    alert("Suka: Bookmarklet error → " + err.message);
  }
})();
